(1755, 'Backkom Sports', 'RG Animation Studios', 'Kids', 'Comedy, Sports', 'Original', 5.74, '2009', 'The 3rd season of Backkom which focuses on him participating and failing at a wide variety of sports. \n\n\n\n\n\nStudioRG Animation Studios\n\nSourceOriginal\n\nDemographicKids', 'Kids', 'Finished', 52, 3, 661, NULL),
(1756, 'Ippatsu Kanta-kun', 'Tatsunoko Production', 'Team Sports', 'Action, Adventure, Comedy, Sports', 'Unknown', 5.98, '1977', 'Kanta lives with his mother, brothers, sisters, and dog named Judeth. He likes baseball, but his mom doesn\'t like him mentioning baseball, because his mother believes this was the cause of her husband\'s death. \r\n\r\n(Source: ANN)\n\n\n\n\n\nStudioTatsunoko Produc', 'Kids', 'Finished', 53, 24, 657, NULL),
(1757, 'Pucca 3', 'Unknown', 'Kids', 'Action, Comedy, Romance', 'Unknown', 6.52, '2018', 'Faced with a threat to the survival of her family restaurant, as well as a rival for Garu\'s heart, Pucca fights for all that she loves.\n\n\n\n\n\nStudioUnknown\n\nSource\n\nDemographicKids', 'Kids', 'Finished', 26, 24, 656, NULL),
(1758, 'Mori no Tonto-tachi', 'Nippon Animation', 'Kids', 'Fantasy', 'Unknown', 6.12, '1984', 'Deep in the forests of Finland live the little people, or Tontus, the elves who work all year round to keep Joulupukki (Santa Claus) supplied with toys for Christmas Eve.\r\n\r\n(Source: ANN)\n\n\n\n\n\nStudiosNippon AnimationShaft\n\nSource\n\nDemographicKids', 'Kids', 'Finished', 23, 25, 655, NULL),
(1759, 'Oraa Guzura Dado (1987)', 'Tatsunoko Production', 'Kids', 'Comedy', 'Unknown', 6.15, '1987', 'Remake of the first series.\n\nWhen Mt. Bikkura erupts a huge egg one day, a chubby little dinosaur name Guzura hatches out of it. The series follows his misadventures as he interacts with humans as well as other animals and creatures\n\n\n\n\n\nStudioTatsunoko P', 'Kids', 'Finished', 44, 30, 655, NULL),
