(1761, 'Little El Cid no Bouken', 'Nippon Animation', 'Historical', 'Adventure', 'Original', 6.24, '1984', 'A boy named Rui Diaz De Vivar wants to become a knight. To do so he must travel the king of Castilla.\n\n\n\n\n\nStudioNippon Animation\n\nSourceOriginal\n\nThemeHistorical\nDemographicKids', 'Kids', 'Finished', 26, 25, 652, NULL),
