(1798, 'Happy?Lucky Bikkuriman', 'Toei Animation', 'Kids', 'Adventure, Comedy, Fantasy', 'Unknown', 6.55, '2006', 'Continuation of the Bikkuriman Series.\n\nGenki Seihikari and his friends join the adventure in order to save seven gods of the White Galaxy.\n\n\n\n\n\nStudioToei Animation\n\nSource\n\nDemographicKids', 'Kids', 'Finished', 46, 24, 440, NULL),
(1799, 'Zhan Long Si Qu', 'Unknown', 'Racing', 'Unknown', 'Unknown', 5.7, '2009', 'Go for Speed is a Chinese anime about Mini 4wds. It was produced by Nanjing Hongying Animation Entertainment Co. Ltd and first aired in China in 2009.  \r\n\r\n(Source: Go For Speed Wiki)\n\n\n\n\n\nStudioUnknown\n\nSource\n\nThemeRacing\nDemographicKids', 'Kids', 'Finished', 64, 24, 435, NULL),
